// Shared formatting helpers. Several modules depend on the exact plain output.
export function formatMoney(amount) {
  const n = Math.round(amount * 100) / 100;
  return String(n);
}

export function pad(value, width) {
  return String(value).padStart(width, " ");
}

src_snapshot.invoice.mjs:
function formatInvoiceAmount(amount) {
  const rounded = Math.round(amount * 100) / 100;
  const [whole, fraction] = rounded.toFixed(2).split(".");
  return `$${whole.replace(/\B(?=(\d{3})+(?!\d))/g, ",")}.${fraction}`;
}

export function renderInvoice(order) {
  const lines = order.items.map(
    (it) => `${it.name} x${it.qty} ${formatInvoiceAmount(it.price * it.qty)}`,
  );
  const total = order.items.reduce((sum, it) => sum + it.price * it.qty, 0);
  lines.push(`TOTAL ${formatInvoiceAmount(total)}`);
  return lines.join("\n");
}

