function formatInvoiceMoney(amount) {
  return `$${Number(formatMoney(amount)).toLocaleString("en-US", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  })}`;
}

export function renderInvoice(order) {
  const lines = order.items.map(
    (it) => `${it.name} x${it.qty} ${formatInvoiceMoney(it.price * it.qty)}`,
  );
  const total = order.items.reduce((sum, it) => sum + it.price * it.qty, 0);
  lines.push(`TOTAL ${formatInvoiceMoney(total)}`);
  return lines.join("\n");
}

